package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

/**
 * Thin HTTP client for the Pinecone vector database.
 *
 * <p>
 * Handles control-plane operations (index creation/lookup via
 * {@code api.pinecone.io}) and data-plane operations (upsert, query, delete)
 * against the resolved index host.
 *
 * <p>
 * The index host is resolved lazily on the first data-plane call via
 * {@link #ensureIndexExists()}. All methods gracefully degrade on errors
 * (catch, log, return empty results) so the rest of the RAG pipeline is never
 * blocked by Pinecone unavailability.
 */
@Service
public class PineconeClient {

	private static final Logger log = LoggerFactory.getLogger(PineconeClient.class);
	private static final String CONTROL_PLANE_URL = "https://api.pinecone.io";
	private static final int EMBEDDING_DIMENSION = 1536;

	private final String apiKey;
	private final String indexName;
	private final String environment;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	/** Resolved at runtime by {@link #ensureIndexExists()}. */
	private volatile String indexHost;

	// ── Inner records ────────────────────────────────────────────────────

	/**
	 * A single vector to be stored in Pinecone.
	 *
	 * <p>
	 * {@code sparseValues} is optional: when non-null, the vector is stored as a
	 * hybrid dense+sparse vector for Pinecone's native hybrid search.
	 */
	public record PineconeVector(String id, float[] values, Map<String, Object> metadata,
			Map<Integer, Float> sparseValues) {

		/**
		 * Backward-compatible 3-arg constructor — {@code sparseValues} defaults to
		 * {@code null} (dense-only).
		 */
		public PineconeVector(String id, float[] values, Map<String, Object> metadata) {
			this(id, values, metadata, null);
		}
	}

	/** A single match returned from a Pinecone query. */
	public record PineconeMatch(String id, double score, Map<String, Object> metadata) {
	}

	// ── Constructors ─────────────────────────────────────────────────────

	/**
	 * Spring-managed constructor. {@link HttpClient} is created internally with a
	 * 10-second connect timeout.
	 */
	@Autowired
	public PineconeClient(@Value("${ai.pinecone.api-key:}") String apiKey,
			@Value("${ai.pinecone.index-name:weekly-commit}") String indexName,
			@Value("${ai.pinecone.environment:us-east-1}") String environment, ObjectMapper objectMapper) {
		this(apiKey, indexName, environment, objectMapper,
				HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build());
	}

	/**
	 * Package-private constructor for unit tests — allows injecting a mock
	 * {@link HttpClient}.
	 */
	PineconeClient(String apiKey, String indexName, String environment, ObjectMapper objectMapper,
			HttpClient httpClient) {
		this.apiKey = apiKey;
		this.indexName = indexName;
		this.environment = environment;
		this.objectMapper = objectMapper;
		this.httpClient = httpClient;

		if (apiKey == null || apiKey.isBlank()) {
			log.warn("PineconeClient: API key is blank — vector operations will be no-ops");
		} else {
			log.info("PineconeClient initialized: indexName={}, environment={}", indexName, environment);
		}
	}

	// ── Public API ───────────────────────────────────────────────────────

	/**
	 * Returns {@code true} when the API key is configured and non-blank.
	 */
	public boolean isAvailable() {
		return apiKey != null && !apiKey.isBlank();
	}

	/**
	 * Lazily ensures the Pinecone index exists and populates {@link #indexHost}.
	 *
	 * <p>
	 * On first call: issues GET {@code /indexes/{indexName}} to the Pinecone
	 * control plane. If the index does not exist (HTTP 404), issues POST
	 * {@code /indexes} to create a serverless index (dimension: 1536, metric:
	 * dotproduct, region: environment). Subsequent calls are no-ops once
	 * {@code indexHost} has been resolved.
	 */
	public void ensureIndexExists() {
		if (!isAvailable() || indexHost != null) {
			return;
		}
		try {
			HttpRequest getReq = controlRequest("GET", "/indexes/" + indexName, null);
			HttpResponse<String> getResp = httpClient.send(getReq, HttpResponse.BodyHandlers.ofString());

			if (getResp.statusCode() == 200) {
				indexHost = parseIndexHost(getResp.body());
				log.info("PineconeClient: resolved index host={}", indexHost);
				return;
			}

			if (getResp.statusCode() == 404) {
				log.info("PineconeClient: index '{}' not found — creating serverless index", indexName);
				createIndex();
				// Fetch again to get the host after creation
				HttpResponse<String> refetchResp = httpClient.send(getReq, HttpResponse.BodyHandlers.ofString());
				if (refetchResp.statusCode() == 200) {
					indexHost = parseIndexHost(refetchResp.body());
					log.info("PineconeClient: index created, host={}", indexHost);
				} else {
					log.warn("PineconeClient: index creation may still be pending (status={})",
							refetchResp.statusCode());
				}
				return;
			}

			log.warn("PineconeClient: unexpected status {} when checking index", getResp.statusCode());
		} catch (Exception e) {
			log.warn("PineconeClient: ensureIndexExists failed: {}", e.getMessage());
		}
	}

	/**
	 * Upserts vectors into the given namespace.
	 *
	 * @param namespace
	 *            Pinecone namespace (use empty string for the default namespace)
	 * @param vectors
	 *            vectors to upsert
	 */
	public void upsert(String namespace, List<PineconeVector> vectors) {
		if (!isAvailable() || vectors == null || vectors.isEmpty()) {
			return;
		}
		ensureIndexExists();
		if (indexHost == null) {
			log.warn("PineconeClient: upsert skipped — index host not resolved");
			return;
		}
		try {
			ObjectNode body = objectMapper.createObjectNode();
			body.put("namespace", namespace != null ? namespace : "");
			ArrayNode vectorsNode = body.putArray("vectors");
			for (PineconeVector v : vectors) {
				ObjectNode vNode = vectorsNode.addObject();
				vNode.put("id", v.id());
				ArrayNode valuesNode = vNode.putArray("values");
				for (float f : v.values()) {
					valuesNode.add(f);
				}
				if (v.metadata() != null && !v.metadata().isEmpty()) {
					vNode.set("metadata", objectMapper.valueToTree(v.metadata()));
				}
				if (v.sparseValues() != null && !v.sparseValues().isEmpty()) {
					vNode.set("sparse_values", buildSparseValuesNode(v.sparseValues()));
				}
			}
			String json = objectMapper.writeValueAsString(body);
			HttpRequest req = dataRequest("POST", "/vectors/upsert", json);
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			if (resp.statusCode() != 200) {
				log.warn("PineconeClient: upsert returned {}: {}", resp.statusCode(), resp.body());
			} else {
				log.debug("PineconeClient: upserted {} vectors to namespace='{}'", vectors.size(), namespace);
			}
		} catch (Exception e) {
			log.warn("PineconeClient: upsert failed: {}", e.getMessage());
		}
	}

	/**
	 * Queries the index for the nearest neighbours of {@code vector} (dense-only).
	 *
	 * @param namespace
	 *            Pinecone namespace
	 * @param vector
	 *            query vector
	 * @param topK
	 *            maximum number of results
	 * @param filter
	 *            optional metadata filter (may be null or empty)
	 * @return list of matches, empty on error
	 */
	public List<PineconeMatch> query(String namespace, float[] vector, int topK, Map<String, Object> filter) {
		return executeQuery(namespace, vector, topK, filter, null);
	}

	/**
	 * Queries the index using hybrid dense+sparse search.
	 *
	 * <p>
	 * When {@code sparseVector} is non-null and non-empty, both the dense vector
	 * and sparse vector are sent to Pinecone for hybrid retrieval. When
	 * {@code sparseVector} is {@code null} or empty, this behaves identically to
	 * the dense-only overload.
	 *
	 * @param namespace
	 *            Pinecone namespace
	 * @param vector
	 *            dense query vector
	 * @param topK
	 *            maximum number of results
	 * @param filter
	 *            optional metadata filter (may be null or empty)
	 * @param sparseVector
	 *            optional sparse vector (token index → weight); may be null
	 * @return list of matches, empty on error
	 */
	public List<PineconeMatch> query(String namespace, float[] vector, int topK, Map<String, Object> filter,
			Map<Integer, Float> sparseVector) {
		return executeQuery(namespace, vector, topK, filter, sparseVector);
	}

	/** Shared implementation for both {@code query()} overloads. */
	private List<PineconeMatch> executeQuery(String namespace, float[] vector, int topK, Map<String, Object> filter,
			Map<Integer, Float> sparseVector) {
		if (!isAvailable() || vector == null || vector.length == 0) {
			return Collections.emptyList();
		}
		ensureIndexExists();
		if (indexHost == null) {
			log.warn("PineconeClient: query skipped — index host not resolved");
			return Collections.emptyList();
		}
		try {
			ObjectNode body = objectMapper.createObjectNode();
			body.put("namespace", namespace != null ? namespace : "");
			body.put("topK", topK);
			body.put("includeMetadata", true);
			ArrayNode vectorNode = body.putArray("vector");
			for (float f : vector) {
				vectorNode.add(f);
			}
			if (filter != null && !filter.isEmpty()) {
				body.set("filter", objectMapper.valueToTree(filter));
			}
			if (sparseVector != null && !sparseVector.isEmpty()) {
				body.set("sparse_vector", buildSparseValuesNode(sparseVector));
			}
			String json = objectMapper.writeValueAsString(body);
			HttpRequest req = dataRequest("POST", "/query", json);
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			if (resp.statusCode() != 200) {
				log.warn("PineconeClient: query returned {}: {}", resp.statusCode(), resp.body());
				return Collections.emptyList();
			}
			return parseMatches(resp.body());
		} catch (Exception e) {
			log.warn("PineconeClient: query failed: {}", e.getMessage());
			return Collections.emptyList();
		}
	}

	/**
	 * Deletes vectors by ID from the given namespace.
	 *
	 * @param namespace
	 *            Pinecone namespace
	 * @param ids
	 *            IDs to delete
	 */
	public void deleteByIds(String namespace, List<String> ids) {
		if (!isAvailable() || ids == null || ids.isEmpty()) {
			return;
		}
		ensureIndexExists();
		if (indexHost == null) {
			log.warn("PineconeClient: deleteByIds skipped — index host not resolved");
			return;
		}
		try {
			ObjectNode body = objectMapper.createObjectNode();
			body.put("namespace", namespace != null ? namespace : "");
			ArrayNode idsNode = body.putArray("ids");
			ids.forEach(idsNode::add);
			String json = objectMapper.writeValueAsString(body);
			HttpRequest req = dataRequest("POST", "/vectors/delete", json);
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			if (resp.statusCode() != 200) {
				log.warn("PineconeClient: deleteByIds returned {}: {}", resp.statusCode(), resp.body());
			} else {
				log.debug("PineconeClient: deleted {} vectors from namespace='{}'", ids.size(), namespace);
			}
		} catch (Exception e) {
			log.warn("PineconeClient: deleteByIds failed: {}", e.getMessage());
		}
	}

	// ── Private helpers ──────────────────────────────────────────────────

	private void createIndex() throws Exception {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("name", indexName);
		body.put("dimension", EMBEDDING_DIMENSION);
		body.put("metric", "dotproduct");
		ObjectNode spec = body.putObject("spec");
		ObjectNode serverless = spec.putObject("serverless");
		serverless.put("cloud", "aws");
		serverless.put("region", environment);
		String json = objectMapper.writeValueAsString(body);
		HttpRequest req = controlRequest("POST", "/indexes", json);
		HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
		if (resp.statusCode() != 201 && resp.statusCode() != 200) {
			log.warn("PineconeClient: createIndex returned {}: {}", resp.statusCode(), resp.body());
		}
	}

	private String parseIndexHost(String responseBody) throws Exception {
		JsonNode root = objectMapper.readTree(responseBody);
		String host = root.path("host").asText(null);
		if (host == null || host.isBlank()) {
			throw new IllegalStateException("Pinecone index response missing 'host' field");
		}
		// Ensure scheme is present
		return host.startsWith("http") ? host : "https://" + host;
	}

	private List<PineconeMatch> parseMatches(String responseBody) throws Exception {
		JsonNode root = objectMapper.readTree(responseBody);
		JsonNode matches = root.get("matches");
		if (matches == null || matches.isEmpty()) {
			return Collections.emptyList();
		}
		List<PineconeMatch> result = new ArrayList<>(matches.size());
		for (JsonNode m : matches) {
			String id = m.path("id").asText();
			double score = m.path("score").asDouble();
			Map<String, Object> metadata = Collections.emptyMap();
			if (m.has("metadata")) {
				@SuppressWarnings("unchecked")
				Map<String, Object> meta = objectMapper.treeToValue(m.get("metadata"), Map.class);
				metadata = meta;
			}
			result.add(new PineconeMatch(id, score, metadata));
		}
		return result;
	}

	private HttpRequest controlRequest(String method, String path, String jsonBody) throws Exception {
		HttpRequest.Builder builder = HttpRequest.newBuilder().uri(URI.create(CONTROL_PLANE_URL + path))
				.header("Api-Key", apiKey).header("Content-Type", "application/json").timeout(Duration.ofSeconds(30));
		if ("POST".equals(method) && jsonBody != null) {
			builder.POST(HttpRequest.BodyPublishers.ofString(jsonBody));
		} else {
			builder.method(method, HttpRequest.BodyPublishers.noBody());
		}
		return builder.build();
	}

	private HttpRequest dataRequest(String method, String path, String jsonBody) throws Exception {
		String hostUrl = indexHost.startsWith("http") ? indexHost : "https://" + indexHost;
		HttpRequest.Builder builder = HttpRequest.newBuilder().uri(URI.create(hostUrl + path)).header("Api-Key", apiKey)
				.header("Content-Type", "application/json").timeout(Duration.ofSeconds(30));
		if ("POST".equals(method) && jsonBody != null) {
			builder.POST(HttpRequest.BodyPublishers.ofString(jsonBody));
		} else {
			builder.method(method, HttpRequest.BodyPublishers.noBody());
		}
		return builder.build();
	}

	/**
	 * Serialises a sparse vector ({@code index → weight}) into the Pinecone JSON
	 * format: {@code {"indices":[...], "values":[...]}}.
	 *
	 * <p>
	 * Entries are sorted by index for deterministic output.
	 */
	private com.fasterxml.jackson.databind.node.ObjectNode buildSparseValuesNode(Map<Integer, Float> sparseValues) {
		com.fasterxml.jackson.databind.node.ObjectNode node = objectMapper.createObjectNode();
		ArrayNode indicesNode = node.putArray("indices");
		ArrayNode valuesNode = node.putArray("values");
		sparseValues.entrySet().stream().sorted(Map.Entry.comparingByKey()).forEach(e -> {
			indicesNode.add(e.getKey());
			valuesNode.add(e.getValue());
		});
		return node;
	}

	/** Exposed for testing — allows pre-seeding the resolved index host. */
	void setIndexHostForTesting(String host) {
		this.indexHost = host;
	}
}

package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

/**
 * Generates vector embeddings via the OpenRouter embeddings endpoint.
 *
 * <p>
 * Used by the RAG pipeline to convert text chunks and query strings into dense
 * vectors for Pinecone storage and retrieval.
 *
 * <p>
 * Gracefully degrades: returns an empty {@code float[0]} on any error so
 * callers can decide how to handle absent embeddings without propagating
 * exceptions.
 */
@Service
public class EmbeddingService {

	private static final Logger log = LoggerFactory.getLogger(EmbeddingService.class);
	private static final float[] EMPTY = new float[0];

	private final String apiKey;
	private final String baseUrl;
	private final String model;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	/**
	 * Spring-managed constructor. {@link HttpClient} is created internally with a
	 * 10-second connect timeout.
	 */
	@Autowired
	public EmbeddingService(@Value("${ai.openrouter.api-key:}") String apiKey,
			@Value("${ai.openrouter.base-url:https://openrouter.ai/api/v1}") String baseUrl,
			@Value("${ai.embedding.model:openai/text-embedding-3-small}") String model, ObjectMapper objectMapper) {
		this(apiKey, baseUrl, model, objectMapper,
				HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build());
	}

	/**
	 * Package-private constructor for unit tests — allows injecting a mock
	 * {@link HttpClient}.
	 */
	EmbeddingService(String apiKey, String baseUrl, String model, ObjectMapper objectMapper, HttpClient httpClient) {
		this.apiKey = apiKey;
		this.baseUrl = baseUrl;
		this.model = model;
		this.objectMapper = objectMapper;
		this.httpClient = httpClient;

		if (apiKey == null || apiKey.isBlank()) {
			log.warn("EmbeddingService: API key is blank — embeddings will be unavailable");
		} else {
			log.info("EmbeddingService initialized: model={}", model);
		}
	}

	// ── Public API ───────────────────────────────────────────────────────

	/**
	 * Returns {@code true} when the API key is configured and non-blank. Callers
	 * should check this before invoking {@link #embed(String)} to avoid unnecessary
	 * processing.
	 */
	public boolean isAvailable() {
		return apiKey != null && !apiKey.isBlank();
	}

	/**
	 * Generates a vector embedding for the given {@code text}.
	 *
	 * <p>
	 * POSTs to {@code {baseUrl}/embeddings} with body {@code {"model": "...",
	 * "input": ["text"]}} and extracts {@code data[0].embedding} as a
	 * {@code float[]}.
	 *
	 * @param text
	 *            the text to embed; {@code null} or blank returns {@code float[0]}
	 * @return the embedding vector, or {@code float[0]} on any error
	 */
	public float[] embed(String text) {
		if (!isAvailable()) {
			log.debug("EmbeddingService unavailable — API key is blank");
			return EMPTY;
		}
		if (text == null || text.isBlank()) {
			return EMPTY;
		}
		try {
			ObjectNode body = objectMapper.createObjectNode();
			body.put("model", model);
			ArrayNode inputArray = body.putArray("input");
			inputArray.add(text);
			String json = objectMapper.writeValueAsString(body);

			HttpRequest request = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/embeddings"))
					.header("Authorization", "Bearer " + apiKey).header("Content-Type", "application/json")
					.header("HTTP-Referer", "https://weeklycommit.dev").header("X-Title", "Weekly Commit")
					.timeout(Duration.ofSeconds(30)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

			HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

			if (response.statusCode() != 200) {
				log.warn("Embedding API returned HTTP {}: {}", response.statusCode(), response.body());
				return EMPTY;
			}

			return parseEmbedding(response.body());
		} catch (Exception e) {
			log.warn("Embedding request failed: {}", e.getMessage());
			return EMPTY;
		}
	}

	// ── Private helpers ──────────────────────────────────────────────────

	private float[] parseEmbedding(String responseBody) {
		try {
			JsonNode root = objectMapper.readTree(responseBody);
			JsonNode data = root.get("data");
			if (data == null || data.isEmpty()) {
				log.warn("Embedding response missing 'data' field");
				return EMPTY;
			}
			JsonNode embeddingNode = data.get(0).get("embedding");
			if (embeddingNode == null || !embeddingNode.isArray()) {
				log.warn("Embedding response missing 'embedding' in data[0]");
				return EMPTY;
			}
			float[] result = new float[embeddingNode.size()];
			for (int i = 0; i < embeddingNode.size(); i++) {
				result[i] = (float) embeddingNode.get(i).asDouble();
			}
			return result;
		} catch (Exception e) {
			log.warn("Failed to parse embedding response: {}", e.getMessage());
			return EMPTY;
		}
	}
}

package com.weeklycommit.ai.rag;

import com.weeklycommit.domain.entity.CarryForwardLink;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.entity.Team;
import com.weeklycommit.domain.repository.CarryForwardLinkRepository;
import com.weeklycommit.domain.repository.ManagerCommentRepository;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.TeamRepository;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.Executor;
import java.util.stream.Collectors;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.scheduling.annotation.Async;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Orchestrates embedding and vector-store indexing for domain entities.
 *
 * <p>
 * Each public mutating method is annotated {@link Async} so indexing calls
 * placed at the end of write-path services do not block HTTP response latency.
 * All methods guard on {@link PineconeClient#isAvailable()} and catch all
 * exceptions, ensuring the RAG pipeline never disrupts the primary write path.
 *
 * <p>
 * Vectors are partitioned into Pinecone namespaces by organisation ID, derived
 * by traversing the entity → team → organisation chain.
 */
@Service
public class SemanticIndexService {

	private static final Logger log = LoggerFactory.getLogger(SemanticIndexService.class);

	// ── Entity type constants ─────────────────────────────────────────────
	public static final String TYPE_COMMIT = "commit";
	public static final String TYPE_SCOPE_CHANGE = "scope_change";
	public static final String TYPE_CARRY_FORWARD = "carry_forward";
	public static final String TYPE_MANAGER_COMMENT = "manager_comment";
	public static final String TYPE_TICKET = "ticket";
	public static final String TYPE_PLAN_SUMMARY = "plan_summary";

	private final PineconeClient pineconeClient;
	private final EmbeddingService embeddingService;
	private final ChunkBuilder chunkBuilder;
	private final SparseEncoder sparseEncoder;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ScopeChangeEventRepository scopeChangeRepo;
	private final CarryForwardLinkRepository carryForwardLinkRepo;
	private final ManagerCommentRepository commentRepo;
	private final WorkItemRepository workItemRepo;
	private final TeamRepository teamRepo;
	private final RcdoNodeRepository rcdoNodeRepo;
	private final UserAccountRepository userRepo;
	private final Executor taskExecutor;

	public SemanticIndexService(PineconeClient pineconeClient, EmbeddingService embeddingService,
			ChunkBuilder chunkBuilder, WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			ScopeChangeEventRepository scopeChangeRepo, CarryForwardLinkRepository carryForwardLinkRepo,
			ManagerCommentRepository commentRepo, WorkItemRepository workItemRepo, TeamRepository teamRepo,
			RcdoNodeRepository rcdoNodeRepo, UserAccountRepository userRepo, SparseEncoder sparseEncoder,
			@Qualifier("taskExecutor") Executor taskExecutor) {
		this.pineconeClient = pineconeClient;
		this.embeddingService = embeddingService;
		this.chunkBuilder = chunkBuilder;
		this.sparseEncoder = sparseEncoder;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.scopeChangeRepo = scopeChangeRepo;
		this.carryForwardLinkRepo = carryForwardLinkRepo;
		this.commentRepo = commentRepo;
		this.workItemRepo = workItemRepo;
		this.teamRepo = teamRepo;
		this.rcdoNodeRepo = rcdoNodeRepo;
		this.userRepo = userRepo;
		this.taskExecutor = taskExecutor;
	}

	// ── Async indexing ────────────────────────────────────────────────────

	/**
	 * Embeds and upserts the entity identified by {@code entityType} /
	 * {@code entityId} into Pinecone.
	 *
	 * <p>
	 * Runs asynchronously so it never blocks the write path. All failures are
	 * caught and logged.
	 */
	@Async
	@Transactional(readOnly = true)
	public void indexEntity(String entityType, UUID entityId) {
		if (!pineconeClient.isAvailable()) {
			return;
		}
		try {
			doIndex(entityType, entityId);
		} catch (Exception e) {
			log.warn("SemanticIndexService: failed to index {}:{} — {}", entityType, entityId, e.getMessage());
		}
	}

	/**
	 * Removes the vector for the given entity from Pinecone.
	 *
	 * <p>
	 * Runs asynchronously. Failure is logged but does not propagate.
	 */
	@Async
	public void deleteEntity(String entityType, UUID entityId) {
		if (!pineconeClient.isAvailable()) {
			return;
		}
		try {
			String namespace = resolveNamespaceForEntity(entityType, entityId);
			pineconeClient.deleteByIds(namespace, List.of(entityType + ":" + entityId));
		} catch (Exception e) {
			log.warn("SemanticIndexService: failed to delete {}:{} — {}", entityType, entityId, e.getMessage());
		}
	}

	// ── On-demand full reindex ────────────────────────────────────────────

	/**
	 * Kicks off a full reindex of every plan in the background. Returns immediately
	 * with the plan count; indexing continues asynchronously. Intended for
	 * admin/dev use after bulk SQL seed or Pinecone wipes.
	 *
	 * @return number of plans queued for indexing (not yet necessarily completed)
	 */
	@Transactional(readOnly = true)
	public int fullReindex() {
		if (!pineconeClient.isAvailable()) {
			log.warn("SemanticIndexService: fullReindex skipped — Pinecone unavailable");
			return 0;
		}
		List<WeeklyPlan> plans = planRepo.findAll();
		log.info("SemanticIndexService: fullReindex queuing {} plans", plans.size());
		// Use taskExecutor directly to avoid @Async self-invocation proxy bypass.
		taskExecutor.execute(() -> {
			log.info("SemanticIndexService: fullReindex background started — {} plans", plans.size());
			int ok = 0;
			for (WeeklyPlan plan : plans) {
				try {
					reindexPlan(plan);
					ok++;
				} catch (Exception ex) {
					log.warn("SemanticIndexService: fullReindex failed for plan {} — {}", plan.getId(),
							ex.getMessage());
				}
			}
			log.info("SemanticIndexService: fullReindex complete — {}/{} plans indexed", ok, plans.size());
		});
		return plans.size();
	}

	// ── Scheduled daily sweep ─────────────────────────────────────────────

	/**
	 * Re-indexes all entities belonging to plans updated in the last 48 hours.
	 *
	 * <p>
	 * This sweep catches anything that might have been missed during async indexing
	 * (e.g. if Pinecone was temporarily unavailable). Runs at 03:00 UTC daily and
	 * is skipped entirely when Pinecone is unavailable.
	 */
	@Scheduled(cron = "0 0 3 * * *")
	@Transactional(readOnly = true)
	public void dailySweepReindex() {
		if (!pineconeClient.isAvailable()) {
			log.debug("SemanticIndexService: daily sweep skipped — Pinecone unavailable");
			return;
		}
		try {
			Instant cutoff = Instant.now().minus(48, ChronoUnit.HOURS);
			List<WeeklyPlan> plans = planRepo.findUpdatedSince(cutoff);
			log.info("SemanticIndexService: daily sweep indexing {} recently-updated plans", plans.size());

			for (WeeklyPlan plan : plans) {
				try {
					reindexPlan(plan);
				} catch (Exception ex) {
					log.warn("SemanticIndexService: sweep failed for plan {} — {}", plan.getId(), ex.getMessage());
				}
			}
		} catch (Exception e) {
			log.warn("SemanticIndexService: daily sweep failed — {}", e.getMessage());
		}
	}

	// ── Private implementation ────────────────────────────────────────────

	/**
	 * Core indexing logic, shared by {@link #indexEntity} (async) and
	 * {@link #dailySweepReindex} (scheduled).
	 */
	private void doIndex(String entityType, UUID entityId) {
		switch (entityType) {
			case TYPE_COMMIT -> indexCommit(entityId);
			case TYPE_SCOPE_CHANGE -> indexScopeChange(entityId);
			case TYPE_CARRY_FORWARD -> indexCarryForward(entityId);
			case TYPE_MANAGER_COMMENT -> indexManagerComment(entityId);
			case TYPE_TICKET -> indexWorkItem(entityId);
			case TYPE_PLAN_SUMMARY -> indexPlanSummary(entityId);
			default -> log.warn("SemanticIndexService: unknown entityType '{}'", entityType);
		}
	}

	private void reindexPlan(WeeklyPlan plan) {
		// Plan summary
		indexPlanSummaryDirect(plan);

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		// All commits
		for (WeeklyCommit commit : commits) {
			try {
				indexCommitDirect(commit, plan);
			} catch (Exception ex) {
				log.warn("SemanticIndexService: sweep failed for commit {} — {}", commit.getId(), ex.getMessage());
			}
		}

		// All scope-change events
		for (ScopeChangeEvent event : scopeChangeRepo.findByPlanIdOrderByCreatedAtAsc(plan.getId())) {
			try {
				indexScopeChangeDirect(event);
			} catch (Exception ex) {
				log.warn("SemanticIndexService: sweep failed for scope_change {} — {}", event.getId(), ex.getMessage());
			}
		}

		// Carry-forward links for each commit
		for (WeeklyCommit commit : commits) {
			for (CarryForwardLink link : carryForwardLinkRepo.findBySourceCommitId(commit.getId())) {
				try {
					indexCarryForwardDirect(link, commit);
				} catch (Exception ex) {
					log.warn("SemanticIndexService: sweep failed for carry_forward {} — {}", link.getId(),
							ex.getMessage());
				}
			}
		}
	}

	// ── Entity-specific index methods ─────────────────────────────────────

	private void indexCommit(UUID commitId) {
		commitRepo.findById(commitId).ifPresent(
				commit -> planRepo.findById(commit.getPlanId()).ifPresent(plan -> indexCommitDirect(commit, plan)));
	}

	private void indexCommitDirect(WeeklyCommit commit, WeeklyPlan plan) {
		// Resolve full RCDO ancestry path
		String rcdoPath = resolveRcdoPath(commit.getRcdoNodeId());

		// Resolve team name
		String teamName = resolveTeamName(plan.getTeamId());

		// Owner display name
		String ownerName = resolveUserName(commit.getOwnerUserId());

		// Carry-forward lineage
		String cfLineage = null;
		if (commit.getCarryForwardStreak() > 0 && commit.getCarryForwardSourceId() != null) {
			cfLineage = resolveCarryForwardLineage(commit);
		}

		// Linked ticket summary
		String ticketSummary = null;
		if (commit.getWorkItemId() != null) {
			ticketSummary = workItemRepo.findById(commit.getWorkItemId()).map(wi -> wi.getKey() + " " + wi.getTitle()
					+ " [" + (wi.getStatus() != null ? wi.getStatus().name() : "") + "]").orElse(null);
		}

		// Cross-team RCDO note
		String crossTeamNote = resolveCrossTeamRcdoNote(commit.getRcdoNodeId(), plan.getTeamId());

		ChunkBuilder.EnrichmentContext enrichment = new ChunkBuilder.EnrichmentContext(rcdoPath, teamName, ownerName,
				cfLineage, ticketSummary, crossTeamNote);
		ChunkBuilder.ChunkData chunk = chunkBuilder.buildCommitChunk(commit, plan, enrichment);
		String namespace = resolveNamespace(plan.getTeamId());
		upsertChunk(chunk, namespace);
	}

	private void indexScopeChange(UUID eventId) {
		scopeChangeRepo.findById(eventId).ifPresent(this::indexScopeChangeDirect);
	}

	private void indexScopeChangeDirect(ScopeChangeEvent event) {
		WeeklyCommit commit = event.getCommitId() != null
				? commitRepo.findById(event.getCommitId()).orElse(null)
				: null;
		// Resolve plan for temporal + team context
		WeeklyPlan plan = planRepo.findById(event.getPlanId()).orElse(null);
		String weekDate = plan != null && plan.getWeekStartDate() != null ? plan.getWeekStartDate().toString() : null;
		String teamName = plan != null ? resolveTeamName(plan.getTeamId()) : null;
		UUID teamId = plan != null ? plan.getTeamId() : null;

		ChunkBuilder.ChunkData chunk = chunkBuilder.buildScopeChangeChunk(event, commit, weekDate, teamName, teamId);
		String namespace = plan != null ? resolveNamespace(plan.getTeamId()) : "";
		upsertChunk(chunk, namespace);
	}

	private void indexCarryForward(UUID linkId) {
		carryForwardLinkRepo.findById(linkId).ifPresent(link -> {
			WeeklyCommit source = commitRepo.findById(link.getSourceCommitId()).orElse(null);
			indexCarryForwardDirect(link, source);
		});
	}

	private void indexCarryForwardDirect(CarryForwardLink link, WeeklyCommit sourceCommit) {
		// Resolve RCDO path and team for strategic context
		String rcdoPath = sourceCommit != null ? resolveRcdoPath(sourceCommit.getRcdoNodeId()) : null;
		String teamName = null;
		UUID teamId = null;
		String weekStartDate = null;
		String namespace = "";
		if (sourceCommit != null) {
			WeeklyPlan plan = planRepo.findById(sourceCommit.getPlanId()).orElse(null);
			if (plan != null) {
				teamName = resolveTeamName(plan.getTeamId());
				teamId = plan.getTeamId();
				weekStartDate = plan.getWeekStartDate() != null ? plan.getWeekStartDate().toString() : null;
				namespace = resolveNamespace(plan.getTeamId());
			}
		}
		ChunkBuilder.ChunkData chunk = chunkBuilder.buildCarryForwardChunk(link, sourceCommit, rcdoPath, teamName,
				teamId, weekStartDate);
		upsertChunk(chunk, namespace);
	}

	private void indexManagerComment(UUID commentId) {
		commentRepo.findById(commentId)
				.ifPresent(comment -> resolvePlanForManagerComment(comment)
						.ifPresent(plan -> upsertChunk(chunkBuilder.buildManagerCommentChunk(comment, plan),
								resolveNamespace(plan.getTeamId()))));
	}

	private void indexWorkItem(UUID itemId) {
		workItemRepo.findById(itemId).ifPresent(item -> {
			String rcdoPath = resolveRcdoPath(item.getRcdoNodeId());
			String assigneeName = resolveUserName(item.getAssigneeUserId());
			ChunkBuilder.ChunkData chunk = chunkBuilder.buildWorkItemChunk(item, rcdoPath, assigneeName);
			String namespace = resolveNamespace(item.getTeamId());
			upsertChunk(chunk, namespace);
		});
	}

	private void indexPlanSummary(UUID planId) {
		planRepo.findById(planId).ifPresent(this::indexPlanSummaryDirect);
	}

	private void indexPlanSummaryDirect(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		// Owner and team names
		String ownerName = resolveUserName(plan.getOwnerUserId());
		String teamName = resolveTeamName(plan.getTeamId());

		// RCDO effort distribution: resolve each commit's RCDO leaf title and sum
		// points
		String rcdoDist = buildRcdoDistribution(commits);

		ChunkBuilder.ChunkData chunk = chunkBuilder.buildPlanSummaryChunk(plan, commits, ownerName, teamName, rcdoDist);
		String namespace = resolveNamespace(plan.getTeamId());
		upsertChunk(chunk, namespace);
	}

	// ── Enrichment helpers ────────────────────────────────────────────────

	/**
	 * Walks the RCDO tree from a leaf node up to the root Rally Cry and returns the
	 * full ancestry path, e.g.
	 * {@code "Rally Cry: Win Enterprise > DO: Improve Uptime > Outcome: 99.9% SLA"}.
	 *
	 * <p>
	 * Returns {@code null} when the RCDO node ID is null or cannot be resolved.
	 * Stops after 5 levels to guard against cycles.
	 */
	private String resolveRcdoPath(UUID rcdoNodeId) {
		if (rcdoNodeId == null) {
			return null;
		}
		List<String> parts = new ArrayList<>();
		UUID current = rcdoNodeId;
		int maxDepth = 5;
		while (current != null && maxDepth-- > 0) {
			RcdoNode node = rcdoNodeRepo.findById(current).orElse(null);
			if (node == null) {
				break;
			}
			String typeLabel = switch (node.getNodeType()) {
				case RALLY_CRY -> "Rally Cry";
				case DEFINING_OBJECTIVE -> "DO";
				case OUTCOME -> "Outcome";
			};
			parts.add(0, typeLabel + ": " + node.getTitle());
			current = node.getParentId();
		}
		return parts.isEmpty() ? null : String.join(" > ", parts);
	}

	/**
	 * Resolves a team UUID to its display name. Returns {@code null} if absent.
	 */
	private String resolveTeamName(UUID teamId) {
		if (teamId == null) {
			return null;
		}
		return teamRepo.findById(teamId).map(Team::getName).orElse(null);
	}

	/**
	 * Resolves a user UUID to their display name. Returns {@code null} if absent.
	 */
	private String resolveUserName(UUID userId) {
		if (userId == null) {
			return null;
		}
		return userRepo.findById(userId).map(UserAccount::getDisplayName).orElse(null);
	}

	/**
	 * Builds a human-readable carry-forward lineage for a commit with
	 * {@code carryForwardStreak > 0}, e.g.
	 * {@code "Carried forward 3 weeks (original: \"Auth refactor\", week 2026-03-02)"}.
	 */
	private String resolveCarryForwardLineage(WeeklyCommit commit) {
		int streak = commit.getCarryForwardStreak();
		// Walk back to the original commit (up to streak depth)
		UUID sourceId = commit.getCarryForwardSourceId();
		String originalTitle = null;
		String originalWeek = null;
		int hops = 0;
		while (sourceId != null && hops < streak) {
			WeeklyCommit source = commitRepo.findById(sourceId).orElse(null);
			if (source == null) {
				break;
			}
			originalTitle = source.getTitle();
			// Resolve the source plan's week
			WeeklyPlan sourcePlan = planRepo.findById(source.getPlanId()).orElse(null);
			if (sourcePlan != null && sourcePlan.getWeekStartDate() != null) {
				originalWeek = sourcePlan.getWeekStartDate().toString();
			}
			sourceId = source.getCarryForwardSourceId();
			hops++;
		}
		StringBuilder sb = new StringBuilder();
		sb.append("Carried forward ").append(streak).append(" week(s)");
		if (originalTitle != null) {
			sb.append(" (original: \"").append(originalTitle).append("\"");
			if (originalWeek != null) {
				sb.append(", week ").append(originalWeek);
			}
			sb.append(")");
		}
		return sb.toString();
	}

	/**
	 * Checks whether other teams also have commits targeting the same RCDO node and
	 * returns a note like {@code "Also targeted by: Backend, QA"}, or {@code null}
	 * if there is no cross-team overlap.
	 */
	private String resolveCrossTeamRcdoNote(UUID rcdoNodeId, UUID thisTeamId) {
		if (rcdoNodeId == null) {
			return null;
		}
		try {
			List<WeeklyCommit> peerCommits = commitRepo.findByRcdoNodeId(rcdoNodeId);
			Set<UUID> otherTeamIds = peerCommits.stream()
					.map(c -> planRepo.findById(c.getPlanId()).map(WeeklyPlan::getTeamId).orElse(null))
					.filter(tid -> tid != null && !tid.equals(thisTeamId)).collect(Collectors.toSet());
			if (otherTeamIds.isEmpty()) {
				return null;
			}
			String teamNames = otherTeamIds.stream().map(this::resolveTeamName).filter(n -> n != null && !n.isEmpty())
					.collect(Collectors.joining(", "));
			return teamNames.isEmpty() ? null : "Also targeted by: " + teamNames;
		} catch (Exception e) {
			log.debug("SemanticIndexService: cross-team RCDO resolution failed — {}", e.getMessage());
			return null;
		}
	}

	/**
	 * Builds a human-readable RCDO effort distribution for a plan's commits, e.g.
	 * {@code "Improve Uptime: 8pts (3 commits), Reduce Churn: 5pts (2 commits)"}.
	 */
	private String buildRcdoDistribution(List<WeeklyCommit> commits) {
		if (commits == null || commits.isEmpty()) {
			return null;
		}
		// Group by RCDO node ID → (title, total points, count)
		Map<UUID, String> titleCache = new HashMap<>();
		Map<UUID, int[]> stats = new LinkedHashMap<>(); // int[0]=points, int[1]=count
		for (WeeklyCommit c : commits) {
			UUID rcdoId = c.getRcdoNodeId();
			if (rcdoId == null) {
				continue;
			}
			stats.computeIfAbsent(rcdoId, k -> new int[]{0, 0});
			int[] s = stats.get(rcdoId);
			s[0] += c.getEstimatePoints() != null ? c.getEstimatePoints() : 0;
			s[1]++;
			titleCache.computeIfAbsent(rcdoId, k -> rcdoNodeRepo.findById(k).map(RcdoNode::getTitle).orElse("Unknown"));
		}
		if (stats.isEmpty()) {
			return null;
		}
		return stats.entrySet().stream().map(e -> titleCache.getOrDefault(e.getKey(), "Unknown") + ": "
				+ e.getValue()[0] + "pts (" + e.getValue()[1] + " commits)").collect(Collectors.joining(", "));
	}

	// ── Namespace resolution ──────────────────────────────────────────────

	/**
	 * Resolves the Pinecone namespace (organisation ID string) for the given
	 * entity. Returns empty string if the chain cannot be resolved.
	 */
	private String resolveNamespaceForEntity(String entityType, UUID entityId) {
		try {
			return switch (entityType) {
				case TYPE_COMMIT -> commitRepo.findById(entityId).flatMap(c -> planRepo.findById(c.getPlanId()))
						.map(p -> resolveNamespace(p.getTeamId())).orElse("");
				case TYPE_SCOPE_CHANGE ->
					scopeChangeRepo.findById(entityId).flatMap(e -> planRepo.findById(e.getPlanId()))
							.map(p -> resolveNamespace(p.getTeamId())).orElse("");
				case TYPE_CARRY_FORWARD ->
					carryForwardLinkRepo.findById(entityId).flatMap(l -> commitRepo.findById(l.getSourceCommitId()))
							.flatMap(c -> planRepo.findById(c.getPlanId())).map(p -> resolveNamespace(p.getTeamId()))
							.orElse("");
				case TYPE_MANAGER_COMMENT -> commentRepo.findById(entityId).flatMap(this::resolvePlanForManagerComment)
						.map(p -> resolveNamespace(p.getTeamId())).orElse("");
				case TYPE_TICKET ->
					workItemRepo.findById(entityId).map(i -> resolveNamespace(i.getTeamId())).orElse("");
				case TYPE_PLAN_SUMMARY ->
					planRepo.findById(entityId).map(p -> resolveNamespace(p.getTeamId())).orElse("");
				default -> "";
			};
		} catch (Exception e) {
			log.warn("SemanticIndexService: could not resolve namespace for {}:{}", entityType, entityId);
			return "";
		}
	}

	private String resolveNamespace(UUID teamId) {
		if (teamId == null) {
			return "";
		}
		return teamRepo.findById(teamId).map(t -> t.getOrganizationId() != null ? t.getOrganizationId().toString() : "")
				.orElse("");
	}

	private java.util.Optional<WeeklyPlan> resolvePlanForManagerComment(
			com.weeklycommit.domain.entity.ManagerComment comment) {
		if (comment.getPlanId() != null) {
			return planRepo.findById(comment.getPlanId());
		}
		if (comment.getCommitId() != null) {
			return commitRepo.findById(comment.getCommitId()).flatMap(c -> planRepo.findById(c.getPlanId()));
		}
		return java.util.Optional.empty();
	}

	// ── Embed + upsert helper ─────────────────────────────────────────────

	private void upsertChunk(ChunkBuilder.ChunkData chunk, String namespace) {
		if (chunk == null || chunk.text() == null || chunk.text().isBlank()) {
			return;
		}
		float[] embedding = embeddingService.embed(chunk.text());
		if (embedding.length == 0) {
			log.debug("SemanticIndexService: embedding unavailable for chunk '{}' — skipping upsert", chunk.id());
			return;
		}
		Map<String, Object> meta = new HashMap<>(chunk.metadata());
		meta.put("text", chunk.text());

		// Generate sparse vector for hybrid retrieval (graceful degradation on failure)
		java.util.Map<Integer, Float> sparseVector = null;
		try {
			java.util.Map<Integer, Float> sv = sparseEncoder.encode(chunk.text());
			if (!sv.isEmpty()) {
				sparseVector = sv;
			}
		} catch (Exception e) {
			log.debug("SemanticIndexService: sparse encoding failed for chunk '{}' — {}", chunk.id(), e.getMessage());
		}

		pineconeClient.upsert(namespace,
				List.of(new PineconeClient.PineconeVector(chunk.id(), embedding, meta, sparseVector)));
	}
}

package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.evidence.ConfidenceTierCalculator;
import com.weeklycommit.ai.evidence.ConfidenceTierCalculator.ConfidenceTier;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.ai.service.AiSuggestionService;
import com.weeklycommit.domain.entity.Team;
import com.weeklycommit.domain.repository.TeamRepository;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

/**
 * Handles semantic (RAG) queries: embeds the question, retrieves relevant
 * chunks from Pinecone, and synthesises an answer via the LLM.
 *
 * <p>
 * Pipeline:
 * <ol>
 * <li>Intent classification — extracts entity-type filters and time-range from
 * the natural-language question.</li>
 * <li>Embedding — converts the question to a dense vector.</li>
 * <li>Pinecone retrieval — nearest-neighbour search with metadata filters.</li>
 * <li>Answer generation — packs retrieved chunks into a RAG prompt and calls
 * the LLM.</li>
 * <li>Audit — persists the interaction via {@link AiSuggestionService}.</li>
 * </ol>
 *
 * <p>
 * All steps degrade gracefully: if any upstream service is unavailable, the
 * method returns an unavailable {@link RagQueryResult} without throwing.
 */
@Service
public class SemanticQueryService {

	private static final Logger log = LoggerFactory.getLogger(SemanticQueryService.class);
	/**
	 * Retrieve more candidates from Pinecone; the reranker filters down to top-N.
	 */
	private static final int TOP_K = 80;

	// ── Inner records ─────────────────────────────────────────────────────

	/**
	 * A single source item that contributed to a RAG answer.
	 *
	 * @param entityType
	 *            e.g. {@code "commit"}, {@code "plan_summary"}
	 * @param entityId
	 *            the entity UUID string
	 * @param weekStartDate
	 *            ISO week-start date extracted from vector metadata (may be empty)
	 * @param snippet
	 *            brief excerpt from the chunk text
	 */
	public record RagSource(String entityType, String entityId, String weekStartDate, String snippet) {
	}

	/**
	 * Result of a RAG query.
	 *
	 * @param available
	 *            {@code false} if any upstream dependency is unavailable
	 * @param answer
	 *            synthesised natural-language answer (null when unavailable)
	 * @param sources
	 *            retrieved chunks that informed the answer
	 * @param confidence
	 *            model confidence [0.0, 1.0]
	 * @param suggestionId
	 *            ID of the persisted
	 *            {@link com.weeklycommit.domain.entity.AiSuggestion} audit record
	 *            (null when unavailable)
	 */
	public record RagQueryResult(boolean available, String answer, List<RagSource> sources, double confidence,
			UUID suggestionId, ConfidenceTier confidenceTier) {

		/** Convenience factory for a degraded/unavailable result. */
		public static RagQueryResult unavailable() {
			return new RagQueryResult(false, null, List.of(), 0.0, null, ConfidenceTier.INSUFFICIENT);
		}
	}

	// ── Dependencies ──────────────────────────────────────────────────────

	private final PineconeClient pineconeClient;
	private final EmbeddingService embeddingService;
	private final AiProviderRegistry aiProviderRegistry;
	private final AiSuggestionService aiSuggestionService;
	private final ObjectMapper objectMapper;
	private final TeamRepository teamRepo;
	private final SparseEncoder sparseEncoder;
	private final RerankService rerankService;
	private final ConfidenceTierCalculator confidenceTierCalculator;
	private final QueryRewriter queryRewriter;

	public SemanticQueryService(PineconeClient pineconeClient, EmbeddingService embeddingService,
			AiProviderRegistry aiProviderRegistry, AiSuggestionService aiSuggestionService, ObjectMapper objectMapper,
			TeamRepository teamRepo, SparseEncoder sparseEncoder, RerankService rerankService,
			ConfidenceTierCalculator confidenceTierCalculator, QueryRewriter queryRewriter) {
		this.pineconeClient = pineconeClient;
		this.embeddingService = embeddingService;
		this.aiProviderRegistry = aiProviderRegistry;
		this.aiSuggestionService = aiSuggestionService;
		this.objectMapper = objectMapper;
		this.teamRepo = teamRepo;
		this.sparseEncoder = sparseEncoder;
		this.rerankService = rerankService;
		this.confidenceTierCalculator = confidenceTierCalculator;
		this.queryRewriter = queryRewriter;
	}

	// ── Public API ────────────────────────────────────────────────────────

	/**
	 * Executes a RAG query for the given question scoped to a team.
	 *
	 * @param question
	 *            natural-language question from the user
	 * @param teamId
	 *            team scope for Pinecone namespace + metadata filter
	 * @param userId
	 *            requesting user (for audit)
	 * @return query result, never {@code null}; check
	 *         {@link RagQueryResult#available()}
	 */
	public RagQueryResult query(String question, UUID teamId, UUID userId) {
		if (!pineconeClient.isAvailable() || !embeddingService.isAvailable()) {
			log.debug("SemanticQueryService: unavailable (pinecone={}, embedding={})", pineconeClient.isAvailable(),
					embeddingService.isAvailable());
			return RagQueryResult.unavailable();
		}
		if (question == null || question.isBlank()) {
			return RagQueryResult.unavailable();
		}

		try {
			// Step 1a: rewrite the question for better embedding quality
			String rewritten = queryRewriter.rewrite(question);

			// Step 1b: decompose into sub-queries (detects multi-hop questions)
			List<String> subQueries = queryRewriter.decompose(rewritten);

			// Step 2: intent classification (uses the full rewritten question)
			IntentResult intent = classifyIntent(rewritten, teamId, userId);

			// Step 3: build metadata filter
			Map<String, Object> filter = buildFilter(intent, teamId, userId);

			// Step 4: resolve namespace
			String namespace = resolveNamespace(teamId);

			// Step 5: embed and query Pinecone — single query or multi-hop
			List<PineconeClient.PineconeMatch> matches;
			if (subQueries.size() <= 1) {
				// Single query path
				float[] vector = embeddingService.embed(rewritten);
				if (vector.length == 0) {
					log.debug("SemanticQueryService: embedding returned empty vector — unavailable");
					return RagQueryResult.unavailable();
				}
				java.util.Map<Integer, Float> sparseVector = null;
				try {
					java.util.Map<Integer, Float> sv = sparseEncoder.encode(rewritten);
					if (!sv.isEmpty()) {
						sparseVector = sv;
					}
				} catch (Exception ex) {
					log.debug("SemanticQueryService: sparse encoding failed — falling back to dense-only: {}",
							ex.getMessage());
				}
				matches = pineconeClient.query(namespace, vector, TOP_K, filter, sparseVector);
			} else {
				// Multi-hop path: embed each sub-query, merge results
				matches = queryMultiHop(subQueries, namespace, filter);
				if (matches == null) {
					return RagQueryResult.unavailable();
				}
			}

			// Step 5b: rerank candidates to find the most relevant top-N
			List<RerankService.RankedChunk> reranked = rerankService.rerank(rewritten, matches,
					rerankService.getTopN());

			// Step 5c: compute evidence-based confidence tier from the reranked chunks
			ConfidenceTier confidenceTier = confidenceTierCalculator.calculate(toConfidenceMatches(reranked));

			// Step 6 & 7: build RAG prompt context from reranked results and generate
			// answer
			String contextString = buildContextString(rewritten, matches);
			AiContext ragContext = new AiContext(AiContext.TYPE_RAG_QUERY, userId, null, null, Map.of(), Map.of(),
					List.of(), List.of(), buildRagAdditionalContextReranked(rewritten, reranked));
			AiSuggestionResult llmResult = aiProviderRegistry.generateSuggestion(ragContext);

			// Step 7: parse the answer
			RagAnswer ragAnswer = parseRagAnswer(llmResult);

			// Step 8: persist audit record
			com.weeklycommit.domain.entity.AiSuggestion stored = null;
			try {
				stored = aiSuggestionService.storeSuggestion(AiContext.TYPE_RAG_QUERY, userId, null, null,
						contextString, llmResult);
			} catch (Exception ex) {
				log.warn("SemanticQueryService: failed to store suggestion audit record — {}", ex.getMessage());
			}

			// Step 9: return result
			UUID suggestionId = stored != null ? stored.getId() : null;
			return new RagQueryResult(true, ragAnswer.answer(), ragAnswer.sources(), ragAnswer.confidence(),
					suggestionId, confidenceTier);

		} catch (Exception e) {
			log.warn("SemanticQueryService: query failed — {}", e.getMessage());
			return RagQueryResult.unavailable();
		}
	}

	// ── Private pipeline steps ────────────────────────────────────────────

	/**
	 * Calls the LLM for intent classification. Returns safe defaults if the LLM
	 * call fails or returns unparseable JSON.
	 */
	private IntentResult classifyIntent(String question, UUID teamId, UUID userId) {
		try {
			String today = LocalDate.now().toString();
			// Last Monday = the previous Monday relative to today
			LocalDate todayDate = LocalDate.now();
			LocalDate lastMonday = todayDate.with(java.time.DayOfWeek.MONDAY).minusWeeks(1);
			String lastWeekFrom = lastMonday.toString();
			String lastWeekTo = lastMonday.plusDays(6).toString();
			String thisWeekFrom = todayDate.with(java.time.DayOfWeek.MONDAY).toString();
			Map<String, Object> additionalCtx = new HashMap<>();
			additionalCtx.put("question", question);
			additionalCtx.put("teamId", teamId != null ? teamId.toString() : "");
			additionalCtx.put("currentDate", today);
			additionalCtx.put("lastWeekFrom", lastWeekFrom);
			additionalCtx.put("lastWeekTo", lastWeekTo);
			additionalCtx.put("thisWeekFrom", thisWeekFrom);
			AiContext intentContext = new AiContext(AiContext.TYPE_RAG_INTENT, userId, null, null, Map.of(), Map.of(),
					List.of(), List.of(), additionalCtx);
			AiSuggestionResult result = aiProviderRegistry.generateSuggestion(intentContext);
			if (!result.available()) {
				return IntentResult.defaults();
			}
			return parseIntentResult(result.payload());
		} catch (Exception e) {
			log.debug("SemanticQueryService: intent classification failed — {}", e.getMessage());
			return IntentResult.defaults();
		}
	}

	private IntentResult parseIntentResult(String payload) {
		try {
			JsonNode root = objectMapper.readTree(payload);
			List<String> entityTypes = new ArrayList<>();
			JsonNode et = root.path("entityTypes");
			if (et.isArray()) {
				for (JsonNode node : et) {
					entityTypes.add(node.asText());
				}
			}
			List<String> keywords = new ArrayList<>();
			JsonNode kw = root.path("keywords");
			if (kw.isArray()) {
				for (JsonNode node : kw) {
					keywords.add(node.asText());
				}
			}
			JsonNode timeRange = root.path("timeRange");
			String from = timeRange.isObject() ? timeRange.path("from").asText(null) : null;
			String to = timeRange.isObject() ? timeRange.path("to").asText(null) : null;
			String intent = root.path("intent").asText("");
			String userFilter = root.path("userFilter").isMissingNode() || root.path("userFilter").isNull()
					? null
					: root.path("userFilter").asText(null);
			return new IntentResult(intent, userFilter, entityTypes, from, to, keywords);
		} catch (Exception e) {
			log.debug("SemanticQueryService: could not parse intent — using defaults");
			return IntentResult.defaults();
		}
	}

	private Map<String, Object> buildFilter(IntentResult intent, UUID teamId, UUID userId) {
		Map<String, Object> filter = new HashMap<>();
		if (teamId != null) {
			filter.put("teamId", teamId.toString());
		}
		if (intent.userFilter() != null && userId != null
				&& ("self".equalsIgnoreCase(intent.userFilter()) || "me".equalsIgnoreCase(intent.userFilter()))) {
			filter.put("userId", userId.toString());
		}
		// Entity type filter: use $in for multi-type queries.
		if (intent.entityTypes() != null && !intent.entityTypes().isEmpty()) {
			if (intent.entityTypes().size() == 1) {
				filter.put("entityType", intent.entityTypes().get(0));
			} else {
				filter.put("entityType", Map.of("$in", intent.entityTypes()));
			}
		}
		// Date range filter using the numeric weekStartEpochDay field.
		// ISO date strings ("YYYY-MM-DD") are not supported by Pinecone's $gte/$lte,
		// but the equivalent epoch-day long is stored alongside each chunk.
		Map<String, Object> dateRange = new HashMap<>();
		if (intent.timeRangeFrom() != null && !intent.timeRangeFrom().isBlank()) {
			Long epochFrom = ChunkBuilder.toEpochDay(intent.timeRangeFrom());
			if (epochFrom != null)
				dateRange.put("$gte", epochFrom);
		}
		if (intent.timeRangeTo() != null && !intent.timeRangeTo().isBlank()) {
			Long epochTo = ChunkBuilder.toEpochDay(intent.timeRangeTo());
			if (epochTo != null)
				dateRange.put("$lte", epochTo);
		}
		if (!dateRange.isEmpty()) {
			filter.put("weekStartEpochDay", dateRange);
		}
		return filter.isEmpty() ? null : filter;
	}

	private String resolveNamespace(UUID teamId) {
		if (teamId == null) {
			return "";
		}
		return teamRepo.findById(teamId).map(Team::getOrganizationId)
				.map(orgId -> orgId != null ? orgId.toString() : "").orElse("");
	}

	private String buildContextString(String question, List<PineconeClient.PineconeMatch> matches) {
		try {
			Map<String, Object> ctx = new HashMap<>();
			ctx.put("question", question);
			ctx.put("retrievedChunks", matches.size());
			return objectMapper.writeValueAsString(ctx);
		} catch (Exception e) {
			return "{\"question\":\"" + question + "\"}";
		}
	}

	private Map<String, Object> buildRagAdditionalContext(String question, List<PineconeClient.PineconeMatch> matches) {
		List<Map<String, Object>> chunks = matches.stream().map(m -> {
			Map<String, Object> chunk = new HashMap<>();
			chunk.put("id", m.id());
			chunk.put("score", m.score());
			chunk.put("metadata", m.metadata());
			return chunk;
		}).toList();
		Map<String, Object> ctx = new HashMap<>();
		ctx.put("question", question);
		ctx.put("currentDate", LocalDate.now().toString());
		ctx.put("retrievedChunks", chunks);
		return ctx;
	}

	/**
	 * Builds the additional context map for the RAG prompt using the reranked top-N
	 * chunks. Includes the rerank score so the LLM can see which chunks were most
	 * relevant.
	 */
	private Map<String, Object> buildRagAdditionalContextReranked(String question,
			List<RerankService.RankedChunk> reranked) {
		List<Map<String, Object>> chunks = reranked.stream().map(rc -> {
			Map<String, Object> chunk = new HashMap<>();
			chunk.put("id", rc.id());
			chunk.put("score", rc.score());
			chunk.put("rerankScore", rc.rerankScore());
			chunk.put("metadata", rc.metadata());
			return chunk;
		}).toList();
		Map<String, Object> ctx = new HashMap<>();
		ctx.put("question", question);
		ctx.put("currentDate", java.time.LocalDate.now().toString());
		ctx.put("retrievedChunks", chunks);
		return ctx;
	}

	private List<PineconeClient.PineconeMatch> toConfidenceMatches(List<RerankService.RankedChunk> reranked) {
		if (reranked == null || reranked.isEmpty()) {
			return List.of();
		}
		return reranked.stream()
				.map(chunk -> new PineconeClient.PineconeMatch(chunk.id(), chunk.rerankScore(), chunk.metadata()))
				.toList();
	}

	private RagAnswer parseRagAnswer(AiSuggestionResult result) {
		if (!result.available()) {
			return new RagAnswer("AI provider unavailable", List.of(), 0.0);
		}
		try {
			JsonNode root = objectMapper.readTree(result.payload());
			String answer = root.path("answer").asText("No answer generated");
			double confidence = root.path("confidence").asDouble(0.0);

			List<RagSource> sources = new ArrayList<>();
			JsonNode sourcesNode = root.path("sources");
			if (sourcesNode.isArray()) {
				for (JsonNode s : sourcesNode) {
					sources.add(new RagSource(s.path("entityType").asText(""), s.path("entityId").asText(""),
							s.path("weekStartDate").asText(""), s.path("snippet").asText("")));
				}
			}
			return new RagAnswer(answer, sources, confidence);
		} catch (Exception e) {
			log.debug("SemanticQueryService: could not parse RAG answer — {}", e.getMessage());
			return new RagAnswer(result.payload(), List.of(), result.confidence());
		}
	}

	/**
	 * Executes a multi-hop query by embedding each sub-query independently,
	 * querying Pinecone for each, and merging the results.
	 *
	 * <p>
	 * Merge strategy: union of all matches, deduplicated by chunk ID, keeping the
	 * highest score for each chunk. Results are returned sorted by score descending
	 * so the reranker sees the best candidates first.
	 *
	 * <p>
	 * Error handling: if one sub-query fails (e.g. embedding error), it is skipped
	 * and the remaining sub-queries are processed. If <em>all</em> sub-queries
	 * fail, {@code null} is returned to signal that the caller should degrade to
	 * {@link RagQueryResult#unavailable()}.
	 *
	 * @param subQueries
	 *            decomposed sub-queries (2 – {@value QueryRewriter#MAX_SUB_QUERIES}
	 *            elements)
	 * @param namespace
	 *            Pinecone namespace
	 * @param filter
	 *            Pinecone metadata filter (shared across all sub-queries)
	 * @return merged, deduplicated match list sorted by score descending; or
	 *         {@code null} if all sub-queries failed
	 */
	private List<PineconeClient.PineconeMatch> queryMultiHop(List<String> subQueries, String namespace,
			Map<String, Object> filter) {
		// Map from chunk ID → best-scoring match seen so far
		Map<String, PineconeClient.PineconeMatch> best = new LinkedHashMap<>();
		boolean anySuccess = false;

		for (String subQuery : subQueries) {
			try {
				float[] vector = embeddingService.embed(subQuery);
				if (vector.length == 0) {
					log.debug("SemanticQueryService: sub-query embedding returned empty — skipping sub-query");
					continue;
				}

				java.util.Map<Integer, Float> sparseVector = null;
				try {
					java.util.Map<Integer, Float> sv = sparseEncoder.encode(subQuery);
					if (!sv.isEmpty()) {
						sparseVector = sv;
					}
				} catch (Exception ex) {
					log.debug("SemanticQueryService: sparse encoding failed for sub-query — {}", ex.getMessage());
				}

				List<PineconeClient.PineconeMatch> subMatches = pineconeClient.query(namespace, vector, TOP_K, filter,
						sparseVector);
				anySuccess = true;

				// Merge: keep the highest score per chunk ID
				for (PineconeClient.PineconeMatch m : subMatches) {
					best.merge(m.id(), m,
							(existing, incoming) -> incoming.score() > existing.score() ? incoming : existing);
				}
			} catch (Exception ex) {
				log.debug("SemanticQueryService: sub-query '{}' failed — {}", subQuery, ex.getMessage());
			}
		}

		if (!anySuccess) {
			log.debug("SemanticQueryService: all multi-hop sub-queries failed — unavailable");
			return null;
		}

		// Return merged results sorted by score descending
		return best.values().stream().sorted(Comparator.comparingDouble(PineconeClient.PineconeMatch::score).reversed())
				.toList();
	}

	// ── Private helper records ────────────────────────────────────────────

	private record IntentResult(String intent, String userFilter, List<String> entityTypes, String timeRangeFrom,
			String timeRangeTo, List<String> keywords) {

		static IntentResult defaults() {
			return new IntentResult("", null, List.of(), null, null, List.of());
		}
	}

	private record RagAnswer(String answer, List<RagSource> sources, double confidence) {
	}
}

package com.weeklycommit.ai.provider;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.atomic.AtomicReference;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Component;

/**
 * Production AI provider that routes requests through OpenRouter.
 *
 * <p>
 * Activated when {@code ai.provider=openrouter} (the default). Falls back to
 * unavailable when the API key is blank or the service is unreachable.
 *
 * <p>
 * Features:
 * <ul>
 * <li>Per-suggestion-type prompt templates loaded from classpath</li>
 * <li>Cached health check (60 s TTL) to avoid hammering the API</li>
 * <li>Simple rate limiting via token-bucket (10 req/min default)</li>
 * <li>Token counting from response headers for cost tracking</li>
 * <li>Structured output mode (response_format=json_object) eliminates markdown
 * fence parsing</li>
 * <li>One-retry fallback if the model returns non-JSON content</li>
 * </ul>
 */
@Component
@ConditionalOnProperty(name = "ai.provider", havingValue = "openrouter", matchIfMissing = true)
public class OpenRouterAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(OpenRouterAiProvider.class);

	private final String apiKey;
	private final String model;
	private final int maxTokens;
	private final String baseUrl;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	/** Cached availability result: [timestamp, available]. */
	private final AtomicReference<Instant> lastHealthCheck = new AtomicReference<>(Instant.EPOCH);
	private volatile boolean lastHealthResult = false;
	private static final Duration HEALTH_CACHE_TTL = Duration.ofSeconds(60);

	/** Simple rate limiter: track request count per minute window. */
	private final AtomicLong windowStart = new AtomicLong(System.currentTimeMillis());
	private final AtomicLong windowCount = new AtomicLong(0);
	private static final int MAX_REQUESTS_PER_MINUTE = 30;

	/** Running totals for observability. */
	private final AtomicLong totalTokensUsed = new AtomicLong(0);
	private final AtomicLong totalRequests = new AtomicLong(0);

	public OpenRouterAiProvider(@Value("${ai.openrouter.api-key:}") String apiKey,
			@Value("${ai.openrouter.model:anthropic/claude-sonnet-4-20250514}") String model,
			@Value("${ai.openrouter.max-tokens:1024}") int maxTokens,
			@Value("${ai.openrouter.base-url:https://openrouter.ai/api/v1}") String baseUrl,
			ObjectMapper objectMapper) {
		this.apiKey = apiKey;
		this.model = model;
		this.maxTokens = maxTokens;
		this.baseUrl = baseUrl;
		this.objectMapper = objectMapper;
		this.httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build();

		if (apiKey == null || apiKey.isBlank()) {
			log.warn("OpenRouter API key is blank — provider will report unavailable");
		} else {
			log.info("OpenRouterAiProvider initialized: model={}, maxTokens={}", model, maxTokens);
		}
	}

	// ── AiProvider contract ──────────────────────────────────────────────

	@Override
	public String getName() {
		return "openrouter";
	}

	@Override
	public String getVersion() {
		return model;
	}

	@Override
	public boolean isAvailable() {
		if (apiKey == null || apiKey.isBlank()) {
			return false;
		}
		// Cached health check
		Instant now = Instant.now();
		if (Duration.between(lastHealthCheck.get(), now).compareTo(HEALTH_CACHE_TTL) < 0) {
			return lastHealthResult;
		}
		// Fresh check — just verify the API key works with a tiny request
		try {
			HttpRequest req = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/models"))
					.header("Authorization", "Bearer " + apiKey).timeout(Duration.ofSeconds(5)).GET().build();
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			lastHealthResult = resp.statusCode() == 200;
		} catch (Exception e) {
			log.debug("OpenRouter health check failed: {}", e.getMessage());
			lastHealthResult = false;
		}
		lastHealthCheck.set(now);
		return lastHealthResult;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		if (apiKey == null || apiKey.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// Rate limiting
		if (!tryAcquireRate()) {
			log.warn("OpenRouter rate limit exceeded for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}

		String promptVersion = resolvePromptVersion(context.suggestionType());
		String systemPrompt = loadPromptTemplate(context.suggestionType());
		String userMessage = buildUserMessage(context);

		// Retry loop: if the model returns non-JSON content, retry once
		for (int attempt = 1; attempt <= 2; attempt++) {
			try {
				String responseBody = callOpenRouter(systemPrompt, userMessage);
				totalRequests.incrementAndGet();
				return parseResponse(responseBody, context.suggestionType(), promptVersion);
			} catch (ParseException e) {
				if (attempt < 2) {
					log.warn("OpenRouter response parse failed for type={} (attempt {}), retrying: {}",
							context.suggestionType(), attempt, e.getMessage());
				} else {
					log.warn("OpenRouter response parse failed after retry for type={}: {}", context.suggestionType(),
							e.getMessage());
					return AiSuggestionResult.unavailable();
				}
			} catch (Exception e) {
				log.warn("OpenRouter request failed for type={}: {}", context.suggestionType(), e.getMessage());
				return AiSuggestionResult.unavailable();
			}
		}

		return AiSuggestionResult.unavailable();
	}

	// ── HTTP call ────────────────────────────────────────────────────────

	private String callOpenRouter(String systemPrompt, String userMessage) throws IOException, InterruptedException {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("model", model);
		body.put("max_tokens", maxTokens);

		// Structured output: forces the model to return valid JSON without markdown
		// fences
		ObjectNode responseFormat = body.putObject("response_format");
		responseFormat.put("type", "json_object");

		ArrayNode messages = body.putArray("messages");
		messages.addObject().put("role", "system").put("content", systemPrompt);
		messages.addObject().put("role", "user").put("content", userMessage);

		String json = objectMapper.writeValueAsString(body);

		HttpRequest request = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/chat/completions"))
				.header("Authorization", "Bearer " + apiKey).header("Content-Type", "application/json")
				.header("HTTP-Referer", "https://weeklycommit.dev").header("X-Title", "Weekly Commit")
				.timeout(Duration.ofSeconds(30)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

		HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

		if (response.statusCode() != 200) {
			throw new IOException("OpenRouter returned " + response.statusCode() + ": " + response.body());
		}

		// Track tokens from response
		try {
			JsonNode respNode = objectMapper.readTree(response.body());
			JsonNode usage = respNode.get("usage");
			if (usage != null && usage.has("total_tokens")) {
				totalTokensUsed.addAndGet(usage.get("total_tokens").asLong());
			}
		} catch (Exception ignored) {
		}

		return response.body();
	}

	// ── Response parsing ─────────────────────────────────────────────────

	/**
	 * Parses the OpenRouter response body and returns an
	 * {@link AiSuggestionResult}.
	 *
	 * <p>
	 * With {@code response_format=json_object}, the model content is expected to be
	 * valid JSON directly — no markdown fence stripping needed.
	 *
	 * @throws ParseException
	 *             if the response content cannot be parsed as valid JSON (caller
	 *             should retry)
	 *
	 *             <p>
	 *             Package-private for testing.
	 */
	AiSuggestionResult parseResponse(String responseBody, String suggestionType, String promptVersion)
			throws ParseException {
		JsonNode root;
		try {
			root = objectMapper.readTree(responseBody);
		} catch (Exception e) {
			// The outer response envelope itself is malformed — not retry-worthy
			log.warn("Failed to parse OpenRouter response envelope for {}: {}", suggestionType, e.getMessage());
			return AiSuggestionResult.unavailable();
		}

		JsonNode choices = root.get("choices");
		if (choices == null || choices.isEmpty()) {
			return AiSuggestionResult.unavailable();
		}

		String content = choices.get(0).path("message").path("content").asText("");
		if (content.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// With response_format=json_object the content should be valid JSON directly.
		// If it isn't, signal a retry-worthy failure via ParseException.
		JsonNode contentNode;
		try {
			contentNode = objectMapper.readTree(content);
		} catch (JsonProcessingException e) {
			throw new ParseException("Model returned non-JSON content for " + suggestionType + ": "
					+ content.substring(0, Math.min(200, content.length())), e);
		}

		// Extract rationale from the JSON payload if the model provided one
		String rationale = "AI-generated suggestion";
		JsonNode rationaleNode = contentNode.get("rationale");
		if (rationaleNode != null && !rationaleNode.isNull() && !rationaleNode.asText("").isBlank()) {
			rationale = rationaleNode.asText();
		}

		// Extract confidence from the JSON payload; default to 0.5 if absent or
		// out-of-range. Services with richer evidence context (RAG, risk) will
		// override this with an evidence-based tier in their own pipelines.
		double confidence = 0.5;
		JsonNode confidenceNode = contentNode.get("confidence");
		if (confidenceNode != null && !confidenceNode.isNull() && confidenceNode.isNumber()) {
			double parsed = confidenceNode.asDouble();
			if (parsed >= 0.0 && parsed <= 1.0) {
				confidence = parsed;
			}
		}

		return new AiSuggestionResult(true, content, rationale, confidence, model, promptVersion);
	}

	// ── Prompt construction ──────────────────────────────────────────────

	private String loadPromptTemplate(String suggestionType) {
		String filename = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist.txt";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint.txt";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest.txt";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal.txt";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist.txt";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary.txt";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent.txt";
			case AiContext.TYPE_RAG_QUERY -> "rag-query.txt";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight.txt";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight.txt";
			case AiContext.TYPE_WHAT_IF -> "what-if.txt";
			case "FAITHFULNESS_EVAL" -> "faithfulness-eval.txt";
			default -> "generic.txt";
		};
		try {
			ClassPathResource resource = new ClassPathResource("prompts/" + filename);
			return new String(resource.getInputStream().readAllBytes());
		} catch (IOException e) {
			log.debug("Prompt template not found: prompts/{}, using default", filename);
			return "You are a helpful planning assistant for a weekly commitment tool. "
					+ "Respond with valid JSON matching the expected schema.";
		}
	}

	private String buildUserMessage(AiContext context) {
		try {
			Map<String, Object> msg = Map.of("suggestionType", context.suggestionType(), "commitData",
					context.commitData() != null ? context.commitData() : Map.of(), "planData",
					context.planData() != null ? context.planData() : Map.of(), "historicalCommits",
					context.historicalCommits() != null ? context.historicalCommits() : java.util.List.of(), "rcdoTree",
					context.rcdoTree() != null ? context.rcdoTree() : java.util.List.of(), "additionalContext",
					context.additionalContext() != null ? context.additionalContext() : Map.of());
			return objectMapper.writeValueAsString(msg);
		} catch (Exception e) {
			return "{}";
		}
	}

	/**
	 * Resolves the prompt version identifier for the given suggestion type. Uses
	 * the base prompt filename as the version key with a "-v1" suffix. When A/B
	 * testing, this method can be extended to read from feature flags and load
	 * variant templates (e.g. "commit-draft-assist-v2.txt").
	 */
	private String resolvePromptVersion(String suggestionType) {
		String base = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent";
			case AiContext.TYPE_RAG_QUERY -> "rag-query";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight";
			case AiContext.TYPE_WHAT_IF -> "what-if";
			default -> "generic";
		};
		// commit-draft-assist was updated to v2 (added title length rule + example).
		if ("commit-draft-assist".equals(base)) {
			return base + "-v2";
		}
		return base + "-v1";
	}

	private boolean tryAcquireRate() {
		long now = System.currentTimeMillis();
		long windowMs = 60_000;
		if (now - windowStart.get() > windowMs) {
			windowStart.set(now);
			windowCount.set(0);
		}
		return windowCount.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
	}

	// ── Observability ────────────────────────────────────────────────────

	/** Total tokens consumed across all requests (for metrics). */
	public long getTotalTokensUsed() {
		return totalTokensUsed.get();
	}

	/** Total requests made (for metrics). */
	public long getTotalRequests() {
		return totalRequests.get();
	}

	// ── Inner types ──────────────────────────────────────────────────────

	/**
	 * Thrown by {@link #parseResponse} when the model response content is not valid
	 * JSON. The caller should retry the request.
	 *
	 * <p>
	 * Package-private for testing.
	 */
	static class ParseException extends Exception {

		ParseException(String message, Throwable cause) {
			super(message, cause);
		}
	}
}

